/*
 * sage_shell_entry.c
 * C shim: registers OS native callbacks into MetalVM, loads pre-compiled
 * sage_shell bytecode, and runs the SageLang shell.
 *
 * The bytecode arrays are generated by scripts/compile_sage_shell.sh and
 * placed in sage_shell_bytecode.h at build time.
 */

