/* -----------------------------------------------------------------------
 * VM instance for the Sage shell (persistent across prompt cycles)
 * --------------------------------------------------------------------- */
static MetalVM g_sage_shell_vm;
static int     g_sage_shell_init = 0;

/* -----------------------------------------------------------------------
 * I/O bridge
 * --------------------------------------------------------------------- */
static void bridge_write_char(char c) { console_putc(c); }

static int bridge_read_char(void) {
    KeyEvent ev;
    if (!keyboard_wait_event(&ev)) return -1;
    if (!ev.pressed) return -1;
    return (int)(unsigned char)ev.ascii;
}

/* -----------------------------------------------------------------------
 * Helper: get string arg safely
 * --------------------------------------------------------------------- */
static const char *arg_str(MetalVM *vm, MetalValue *args, int argc, int i) {
    if (i >= argc || args[i].type != MV_STR) return "";
    return metal_string_get(vm, args[i].as.str_idx);
}

static long long arg_num(MetalValue *args, int argc, int i) {
    if (i >= argc || args[i].type != MV_NUM) return 0;
    union { double d; uint64_t u; } v; v.u = args[i].as.num_bits;
    return (long long)v.d;
}

static MetalValue mv_str_lit(MetalVM *vm, const char *s) {
    int n = 0; while (s[n]) n++;
    return mv_str(vm, s, n);
}

static MetalValue mv_dbl(double d) {
    union { double d; uint64_t u; } v; v.d = d;
    return mv_num(v.u);
}

/* -----------------------------------------------------------------------
 * Native callback implementations
 * --------------------------------------------------------------------- */

/* --- Output --- */
static MetalValue n_write_char(MetalVM *vm, MetalValue *a, int c) {
    (void)vm; console_putc((char)(int)arg_num(a,c,0)); return mv_nil();
}
static MetalValue n_write_str(MetalVM *vm, MetalValue *a, int c) {
    (void)vm; console_write(arg_str(vm,a,c,0)); return mv_nil();
}

/* --- Input --- */
static MetalValue n_read_char(MetalVM *vm, MetalValue *a, int c) {
    (void)vm; (void)a; (void)c;
    return mv_dbl((double)bridge_read_char());
}
static MetalValue n_poll_char(MetalVM *vm, MetalValue *a, int c) {
    (void)vm; (void)a; (void)c;
    KeyEvent ev;
    if (keyboard_poll_event(&ev) && ev.pressed) return mv_dbl((double)(unsigned char)ev.ascii);
    return mv_dbl(-1.0);
}

