/* -----------------------------------------------------------------------
 * Register all natives
 * --------------------------------------------------------------------- */
static void register_natives(MetalVM *vm) {
#define REG(name, fn) metal_vm_register_native(vm, name, fn)
    /* Output */
    REG("os_write_char",    n_write_char);
    REG("os_write_str",     n_write_str);
    /* Input */
    REG("os_read_char",     n_read_char);
    REG("os_poll_char",     n_poll_char);
    /* Color */
    REG("os_set_color_hex", n_set_color_hex);
    REG("os_set_color",     n_set_color);
    REG("os_get_color",     n_get_color);
    /* Console */
    REG("os_console_clear", n_console_clear);
    REG("os_cursor_home",   n_cursor_home);
    /* String utils */
    REG("len",              n_len);
    REG("os_strlen",        n_strlen);
    REG("os_streq",         n_streq);
    REG("os_char_at",       n_char_at);
    REG("os_substr",        n_substr);
    REG("os_str_chop",      n_str_chop);
    REG("os_chr",           n_chr);
    REG("os_num_to_str",    n_num_to_str);
    REG("os_array_push",    n_array_push);
    /* System info */
    REG("os_version_string",n_version_string);
    REG("os_input_backend", n_input_backend);
    REG("os_fb_available",  n_fb_available);
    REG("os_fb_base_str",   n_fb_base_str);
    REG("os_fb_width_str",  n_fb_width_str);
    REG("os_fb_height_str", n_fb_height_str);
    REG("os_fb_pps_str",    n_fb_pps_str);
    REG("os_ram_used_mb",   n_ram_used_mb);
    REG("os_ram_total_mb",  n_ram_total_mb);
    REG("os_ram_used_str",  n_ram_used_str);
    REG("os_ram_total_str", n_ram_total_str);
    REG("os_cpu_percent",   n_cpu_percent);
    REG("os_battery_percent",n_battery_percent);
    REG("os_uptime_str",    n_uptime_str);
    /* btop helpers */
    REG("os_draw_bar",      n_draw_bar);
    REG("os_delay_ms",      n_delay_ms);
    /* Kernel commands */
    REG("os_ls",            n_ls);
    REG("os_cat",           n_cat);
    REG("os_mkdir",         n_mkdir);
    REG("os_touch",         n_touch);
    REG("os_rm",            n_rm);
    REG("os_stat",          n_stat);
    REG("os_write",         n_write);
    REG("os_execelf",       n_execelf);
    REG("os_keydebug",      n_keydebug);
    REG("os_dmesg_dump",    n_dmesg_dump);
    REG("os_status_print",  n_status_print);
    REG("os_status_refresh",n_status_refresh);
    REG("os_sysinfo",       n_sysinfo);
    REG("os_timer_info",    n_timer_info);
    REG("os_smp_info",      n_smp_info);
    REG("os_smp_boot_aps",  n_smp_boot_aps);
    REG("os_battery_info",  n_battery_info);
    REG("os_pci_info",      n_pci_info);
    REG("os_sdhci_info",    n_sdhci_info);
    REG("os_acpi_summary",  n_acpi_summary);
    REG("os_acpi_tables",   n_acpi_tables);
    REG("os_acpi_fadt",     n_acpi_fadt);
    REG("os_acpi_madt",     n_acpi_madt);
    REG("os_acpi_lid",      n_acpi_lid);
    REG("os_acpi_battery",  n_acpi_battery);
    REG("os_shutdown",      n_shutdown);
    REG("os_suspend",       n_suspend);
    REG("os_halt",          n_halt);
    REG("os_reboot",        n_reboot);
    REG("os_qemu_exit",     n_qemu_exit);
    REG("os_sage_exec",     n_sage_exec);
#undef REG
}

/* -----------------------------------------------------------------------
 * sage_shell_run — public entry point called from shell.c "sageshell" command
 * --------------------------------------------------------------------- */
void sage_shell_run(void) {
    if (!g_sage_shell_init) {
        metal_vm_init(&g_sage_shell_vm);
        g_sage_shell_vm.write_char = bridge_write_char;
        g_sage_shell_vm.read_char  = bridge_read_char;
        register_natives(&g_sage_shell_vm);
        g_sage_shell_init = 1;
    } else {
        /* Reset execution state but keep registered natives + string pool */
        g_sage_shell_vm.sp          = 0;
        g_sage_shell_vm.scope_depth = 0;
        g_sage_shell_vm.halted      = 0;
        g_sage_shell_vm.error       = 0;
        g_sage_shell_vm.error_msg   = 0;
        g_sage_shell_vm.heap_used    = 0;
    }

    /*
     * Load pre-compiled binary bytecode artifact (SGVM).
     * sage_shell_bytecode[] is generated by scripts/compile_sage_shell.sh
     * and embedded via sage_shell_bytecode.h at build time.
     */
    if (!metal_vm_load_binary(&g_sage_shell_vm,
                             sage_shell_bytecode,
                             (int)sage_shell_bytecode_len)) {
        console_write("\nsageshell: error loading bytecode artifact\n");
        return;
    }

    int result = metal_vm_run(&g_sage_shell_vm);
    if (result < 0) {
        console_write("\nsageshell: runtime error: ");
        console_write(g_sage_shell_vm.error_msg
                      ? g_sage_shell_vm.error_msg : "unknown");
        console_write("\n");
    }
}
